#include <stdio.h>
#define MOD 1000000009
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        char colors[N + 1];
        int positions[M];
        for (int i = 0; i < M; i++) {
            char color;
            int position;
            scanf(" %c %d", &color, &position);
            positions[i] = position;
            colors[position - 1] = color;
        }
        long long result = 1;
        int unique = 0;
        for (int i = 0; i < N; i++) {
            if (colors[i] != 0 && (i == 0 || colors[i] != colors[i - 1])) {
                unique++;
            }
        }
        for (int i = 1; i <= unique; i++) {
            result = (result * i) % MOD;
        }
        printf("%lld\n", result);
    }
    return 0;
}

