const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000009;
const nextLine = () => lines[idx++];
const nextInt = () => parseInt(nextLine());
const nextInts = () => nextLine().split(' ').map(x => parseInt(x));
const nextString = () => nextLine();
for (let T = nextInt(); T-- > 0;) {
    const [N, M] = nextInts();
    const colors = new Array(N).fill(0);
    const positions = [];
    for (let i = 0; i < M; i++) {
        const [color, position] = nextString().split(' ');
        positions.push(parseInt(position));
        colors[parseInt(position) - 1] = color;
    }
    let result = 1;
    let unique = 0;
    for (let i = 0; i < N; i++) {
        if (colors[i] != 0 && (i == 0 || colors[i] != colors[i - 1])) {
            unique++;
        }
    }
    for (let i = 1; i <= unique; i++) {
        result = (result * i) % MOD;
    }
    console.log(result);
}
